//! Admission-by-trust — the score->gate stage that closes the oath loop.
//!
//! After swear -> bind -> prove -> enforce, the breach audit feeds REPUTATION:
//! trust attaches to the STABLE spawner identity (the UCAN holder DID), and a
//! spawner whose trust falls below the admission floor has its spawns DENIED.
//!
//! Covered here, end to end through `ops::spawn` (with a fake monster-guard so no
//! real runtime is needed):
//!   1. A spawner with no breach history is trust 1.0 and is ADMITTED (default
//!      behavior unchanged).
//!   2. A spawner with enough recorded breaches to fall below the floor is DENIED
//!      with the trust-floor error.
//!   3. The floor is overridable via `MONSTER_SWARM_MIN_TRUST` (raise it to deny
//!      a single-breach spawner; lower it to 0 to disable the gate).
//!   4. Breach records carry `spawned_by` from the ledger, so an enforced breach
//!      lands in the audit attributed to the spawner.
//!
//! Each test owns a per-name temp `$MONSTER_GUARD_HOME`; they share the global
//! env so a mutex serializes them.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;
use std::sync::Mutex;

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::breach;
use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, BreachRequest, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;
use monster_swarm::trust;

static ENV_GUARD: Mutex<()> = Mutex::new(());

/// Fake `monster-guard`: delegate + revoke exit 0; run stays alive briefly so the
/// supervisor pid is live when the ledger is saved.
fn fake_guard(dir: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = "#!/bin/sh\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n";
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

fn fake_node(dir: &PathBuf) -> PathBuf {
    let node = dir.join("fake-node");
    std::fs::write(&node, "#!/bin/sh\nexit 0\n").unwrap();
    std::fs::set_permissions(&node, std::fs::Permissions::from_mode(0o755)).unwrap();
    node
}

/// A capability granting agent/spawn + agent/reap rooted at the resident root.
/// The leaf aud (the holder/spawner DID) is the root's own DID.
fn full_ucan() -> (String, String) {
    let root = store::ensure_root().expect("root");
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    let ucan = issue(&root, root.did(), &caps, 3600, &IssueOptions::default()).expect("ucan");
    (ucan, root.did().to_string())
}

fn spawn_req(ucan: &str, id: &str) -> SpawnRequest {
    SpawnRequest {
        ucan: ucan.to_string(),
        node: "fake-node".into(),
        id: Some(id.to_string()),
        caste: Caste::Scout,
        caps: vec!["net".into()],
        lease_secs: 60,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec![],
        qspec: None,
        oath: None,
        teleport: None,
    }
}

/// Seed the breach audit with `n` breaches all attributed to `spawner` (the
/// canonical append path, so the on-disk format is real).
fn seed_breaches(spawner: &str, n: usize) {
    for i in 0..n {
        breach::append(breach::new_breach(
            format!("ghost{i}"),
            format!("agent-ghost{i}"),
            None,
            None,
            "scout".into(),
            "conduct: seeded prior breach".into(),
            "did:key:zReporter".into(),
            false,
            spawner.to_string(),
        ))
        .expect("seed breach");
    }
}

struct Home {
    path: PathBuf,
}

impl Home {
    fn new(name: &str) -> Home {
        let path = std::env::temp_dir().join(format!("monster-swarm-{name}-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&path);
        std::fs::create_dir_all(&path).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &path);
        let bindir = path.join("bin");
        std::fs::create_dir_all(&bindir).unwrap();
        std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
        fake_node(&bindir);
        std::env::set_var("MONSTER_SWARM_NODES", &bindir);
        Home { path }
    }
}

impl Drop for Home {
    fn drop(&mut self) {
        std::env::remove_var("MONSTER_GUARD_HOME");
        std::env::remove_var("MONSTER_GUARD_BIN");
        std::env::remove_var("MONSTER_SWARM_NODES");
        std::env::remove_var("MONSTER_SWARM_MIN_TRUST");
        let _ = std::fs::remove_dir_all(&self.path);
    }
}

#[test]
fn clean_spawner_is_admitted_and_low_trust_spawner_is_denied() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("trustadmit");
    let (ucan, spawner) = full_ucan();

    // (1) No breach history -> trust 1.0 -> admitted (default behavior).
    assert_eq!(trust::trust_of(&spawner), 1.0, "no breaches -> full trust");
    ops::spawn(spawn_req(&ucan, "clean")).expect("a clean spawner is admitted");
    assert!(store::load_fleet().find("clean").is_some(), "clean agent spawned");

    // (2) Seed three breaches against this spawner -> trust 0.0 -> below the
    //     default floor (0.34) -> the next spawn is DENIED.
    seed_breaches(&spawner, 3);
    assert_eq!(trust::trust_of(&spawner), 0.0, "3 breaches floors trust at 0.0");

    let err = match ops::spawn(spawn_req(&ucan, "denied")) {
        Ok(_) => panic!("low-trust spawn must be denied"),
        Err(e) => e,
    };
    assert!(err.contains("spawn denied"), "trust-floor denial: {err}");
    assert!(err.contains("trust"), "names trust: {err}");
    assert!(err.contains("3 prior oath breaches"), "names the breach count: {err}");
    assert!(store::load_fleet().find("denied").is_none(), "denied agent is not in the ledger");
}

#[test]
fn min_trust_env_overrides_the_floor() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("trustenv");
    let (ucan, spawner) = full_ucan();

    // One breach -> trust 0.66, which clears the default floor (0.34).
    seed_breaches(&spawner, 1);
    assert!((trust::trust_of(&spawner) - 0.66).abs() < 1e-9);
    assert_eq!(ops::min_trust(), 0.34, "default floor");
    ops::spawn(spawn_req(&ucan, "ok-at-default")).expect("0.66 clears the 0.34 floor");

    // Raise the floor above 0.66 via env -> the same spawner is now DENIED.
    std::env::set_var("MONSTER_SWARM_MIN_TRUST", "0.8");
    assert_eq!(ops::min_trust(), 0.8, "env overrides the floor");
    let err = match ops::spawn(spawn_req(&ucan, "now-denied")) {
        Ok(_) => panic!("raising the floor denies a once-admissible spawner"),
        Err(e) => e,
    };
    assert!(err.contains("spawn denied"), "{err}");

    // Drop the floor to 0.0 -> the gate is effectively disabled even at trust 0.0.
    std::env::set_var("MONSTER_SWARM_MIN_TRUST", "0.0");
    seed_breaches(&spawner, 5); // pile on -> trust 0.0
    assert_eq!(trust::trust_of(&spawner), 0.0);
    ops::spawn(spawn_req(&ucan, "floor-disabled"))
        .expect("a 0.0 floor admits even a fully-distrusted spawner");
}

#[test]
fn enforced_breach_attributes_spawned_by_in_the_audit() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("trustattr");
    let (ucan, spawner) = full_ucan();

    // Spawn then breach a real agent; the breach record must carry spawned_by
    // (the spawner DID) read from the ledger before the reap removed it.
    ops::spawn(spawn_req(&ucan, "rogue")).expect("spawn");
    let rec = store::load_fleet().find("rogue").expect("ledger").clone();
    assert_eq!(rec.spawned_by, spawner, "ledger records the spawner DID");

    ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "rogue".into(),
        reason: "conduct: went rogue".into(),
        sig_hex: None,
    })
    .expect("breach");

    let log = ops::breaches();
    assert_eq!(log.len(), 1);
    assert_eq!(log[0].spawned_by, spawner, "the breach is attributed to the spawner");

    // And that one breach has dropped the spawner's trust below 1.0.
    assert!((trust::trust_of(&spawner) - 0.66).abs() < 1e-9, "one enforced breach -> 0.66");

    // ops::trusts() surfaces the spawner row.
    let rows = ops::trusts();
    assert_eq!(rows.len(), 1);
    assert_eq!(rows[0].did, spawner);
    assert_eq!(rows[0].breaches, 1);
}
